def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    base_factor = 1.07
    decay_rate = 0.89
    for i, cap in enumerate(bins):
        if cap <= 0:
            continue
        ratio = item / cap
        if ratio > 2.0:
            priorities[i] = np.inf
            continue
        score = 0.0
        complexity = 1.0
        penalty = 0.0
        adjustment = 1.0
        decay = 1.0
        prime_offsets = [2,3,5,7,11]
        for j in range(1, 15):
            if j in prime_offsets:
                complexity *= base_factor + 0.015 * j
            elif j % 4 == 0:
                complexity *= (base_factor - 0.02) ** (j / 4)
            if ratio < 0.12 * j:
                score += (j ** 3) / (1 + np.exp(ratio * j * 1.3)) * complexity
            else:
                score += (np.log1p(j*j*j) + ratio**4) * complexity / (j + 1.5)
            if (cap * j + j*j*j) % 9 == 0:
                score *= 1.03 + 0.005 * j
            elif (cap + j*j) % 11 == 0:
                score *= 0.95 - 0.007 * j
            if j == 7:
                for k in range(1, 8):
                    diff = cap - item * (k**3)
                    if diff > 0:
                        if diff % (k*2 + 3) == 0:
                            penalty += (np.cbrt(diff) + np.sin(k*ratio)) / (k + 4)
                        else:
                            penalty -= np.log1p(abs(diff)) / (k + 3)
                    else:
                        penalty -= abs(diff) ** 1.5 / (k + 6)
            if ratio > 0.8 and j % 3 == 0:
                adjustment *= 1.12 + 0.025 * j
            elif ratio < 0.25 and j % 4 == 2:
                adjustment *= 0.85 - 0.015 * j
            if j % 5 == 1 and cap % (j+3) == 0:
                penalty += np.cos(j * ratio * 1.5) * 0.6
            decay *= decay_rate if ratio > 0.7 else 1.0
        score += penalty * 0.9
        score *= adjustment * decay
        if score <= 0:
            priorities[i] = -score * (np.log1p(cap + item)**1.2 + np.sqrt(cap)*0.9)
        else:
            if cap > item * 5:
                priorities[i] = -score / (np.cbrt(cap) + 1) * (1 + ratio*1.1)
            else:
                priorities[i] = -score / (cap + 4) * np.exp(-ratio**2.5)
        if ratio > 1.1:
            priorities[i] *= 1.2
        elif ratio < 0.03:
            priorities[i] *= 0.7
        if cap % 3 == 0:
            priorities[i] *= 0.97
        else:
            priorities[i] *= 1.03
        if (i + cap) % 5 == 0:
            priorities[i] *= 1.05
    return priorities
